import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;

public class Main {
    static void dfs(int node, HashMap<Integer, List<Integer>> graph, HashSet<Integer> visited, List<Integer> order) {
        visited.add(node);
        order.add(node);
        for (int neighbor : graph.getOrDefault(node, new ArrayList<>())) {
            if (!visited.contains(neighbor)) {
                dfs(neighbor, graph, visited, order);
            }
        }
    }

    public static void main(String[] args) {
        HashMap<Integer, List<Integer>> graph = new HashMap<>();
        int[][] edges = {{0, 1}, {0, 2}, {1, 3}, {2, 3}, {3, 4}};
        for (int[] e : edges) {
            graph.computeIfAbsent(e[0], k -> new ArrayList<>()).add(e[1]);
            graph.computeIfAbsent(e[1], k -> new ArrayList<>()).add(e[0]);
        }

        List<Integer> order = new ArrayList<>();
        dfs(0, graph, new HashSet<>(), order);
        System.out.println(order);  // [0, 1, 3, 2, 4]
    }
}

